INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('VET_CONTENT: Le pattern interrupt textuel: commencer par une phrase qui contredit une croyance populaire. "Le SEO est mort" → attire 5x plus de lecteurs.', 'Pattern interrupt: contredire croyance populaire = 5x lecteurs', 'content', 'best_practice', 0.85, 'veteran', 'system'),
('VET_CONTENT: Le content seeding: partager le contenu dans 5-10 communautes pertinentes (Discord, Slack, Reddit) dans l heure suivant la publication.', 'Content seeding: 5-10 communautes dans 1h post-publication', 'content', 'best_practice', 0.82, 'veteran', 'system'),
('VET_CONTENT: Le content format testing: publier le MEME message dans 3 formats differents (texte, carrousel, video) pour decouvrir le format gagnant.', 'Format testing: meme message 3 formats = decouvrir gagnant', 'content', 'best_practice', 0.82, 'veteran', 'system'),
('VET_CONTENT: Le thread formula LinkedIn: phrase 1 = hook choc, phrases 2-3 = contexte, phrases 4-10 = valeur (1 point par phrase), phrase finale = CTA.', 'Thread LinkedIn: hook → contexte → 1 point/phrase → CTA', 'content', 'best_practice', 0.85, 'veteran', 'system'),
('VET_CONTENT: Le caption layering IG: ligne 1 = hook (visible avant See More), lignes 2-5 = valeur, derniere ligne = CTA + hashtags dans commentaire.', 'Caption IG: hook visible → valeur → CTA + hashtags en commentaire', 'content', 'best_practice', 0.85, 'veteran', 'system'),
('VET_CONTENT: Le content calendar 90-day system: planifier 12 semaines de contenu en 1 journee, puis executer en batch hebdo. Libere le cerveau.', 'Calendar 90j: planifier 12 sem en 1j + execution batch hebdo', 'content', 'best_practice', 0.82, 'veteran', 'system'),
('VET_CONTENT: Le micro-storytelling: chaque post social doit raconter une mini-histoire en 3 temps (situation → tension → resolution) meme en 100 mots.', 'Micro-storytelling: situation → tension → resolution en 100 mots', 'content', 'best_practice', 0.85, 'veteran', 'system'),
('VET_CONTENT: Le expert positioning content: 1 article approfondi/mois (2000+ mots) qui devient LA reference du secteur sur ce sujet. Qualite > quantite.', 'Expert positioning: 1 article 2000+ mots/mois = reference secteur', 'content', 'best_practice', 0.85, 'veteran', 'system'),
('VET_COMMERCIAL: Le SPIN avance: les questions Implication (si vous ne resolvez pas ca, quel impact sur votre CA?) sont les plus puissantes pour creer l urgence.', 'SPIN avance: questions Implication = urgence. Impact CA si pas resolu?', 'commercial', 'best_practice', 0.88, 'veteran', 'system'),
('VET_COMMERCIAL: Le multi-channel persistence: alterner email, LinkedIn, telephone, WhatsApp. Le prospect repond sur SON canal prefere, pas le votre.', 'Multi-channel: alterner email+LI+tel+WhatsApp. Canal du prospect pas le votre', 'commercial', 'best_practice', 0.85, 'veteran', 'system'),
('VET_COMMERCIAL: Le social proof stratifie: pour chaque segment de prospect, avoir 2-3 temoignages du MEME segment. Un restaurateur convainc un restaurateur.', 'Social proof stratifie: temoignages du meme segment. Restaurateur → restaurateur', 'commercial', 'best_practice', 0.88, 'veteran', 'system'),
('VET_COMMERCIAL: Le deal acceleration technique: proposer un avantage time-limited (feature bonus, formation offerte) si le deal ferme avant une date.', 'Deal acceleration: avantage time-limited si closing avant date', 'commercial', 'best_practice', 0.82, 'veteran', 'system'),
('VET_COMMERCIAL: Le loss aversion pitch: ne pas vendre ce que le client GAGNE mais ce qu il PERD en n agissant pas. La perte motive 2x plus que le gain.', 'Loss aversion pitch: ce qu il perd > ce qu il gagne. 2x motivation', 'commercial', 'insight', 0.88, 'veteran', 'system'),
('VET_COMMERCIAL: Le economic buyer alignment: decouvrir les KPIs personnels du decision maker (promotion, budget, objectifs annuels) et aligner la solution dessus.', 'Economic buyer: KPIs personnels (promotion, budget, objectifs). Aligner solution', 'commercial', 'best_practice', 0.85, 'veteran', 'system'),
('VET_EMAIL: Le subject line psychology: les 4 emotions qui ouvrent les emails: curiosite (que s est-il passe?), vanite (vous etes special), urgence (derniere chance), peur (erreur a eviter).', 'Subject emotions: curiosite + vanite + urgence + peur = 4 qui ouvrent', 'email', 'insight', 0.85, 'veteran', 'system'),
('VET_EMAIL: Le email anatomy parfait: from name personnel → subject < 40 chars → preheader complementaire → 1 idee → 1 CTA → PS avec proof.', 'Email parfait: from perso + subject<40 + preheader + 1 idee + 1 CTA + PS proof', 'email', 'best_practice', 0.88, 'veteran', 'system'),
('VET_EMAIL: Le warmup engagement protocol: les 2 premieres semaines d un nouveau domaine, envoyer UNIQUEMENT aux contacts les plus engages (ouvrent toujours).', 'Warmup: 2 premieres semaines = envoyer uniquement aux plus engages', 'email', 'best_practice', 0.88, 'veteran', 'system'),
('VET_EMAIL: Le send time machine learning: analyser l heure d ouverture de chaque contact sur les 30 derniers jours et envoyer a SA meilleure heure.', 'Send time ML: heure ouverture individuelle sur 30j = envoyer a sa meilleure heure', 'email', 'best_practice', 0.85, 'veteran', 'system'),
('VET_EMAIL: Le email re-engagement cascade: J+45 inactif "on a change" → J+60 "ce que vous ratez" → J+75 offre speciale → J+90 "au revoir" + suppression.', 'Re-engagement: J45 change → J60 ratez → J75 offre → J90 au revoir + supprimer', 'email', 'best_practice', 0.82, 'veteran', 'system'),
('VET_SEO: Le keyword universe mapping: classifier tous les mots-cles en clusters par intent → creer 1 page pilier par cluster → lier tout ensemble.', 'Keyword universe: clusters par intent → 1 pilier/cluster → liens', 'seo', 'best_practice', 0.88, 'veteran', 'system'),
('VET_SEO: Le competitive content gap exploit: trouver les mots-cles ou TOUS les concurrents rankent mal (page 2+) et creer LE meilleur contenu.', 'Competitive gap: tous concurrents rankent mal → creer LE meilleur contenu', 'seo', 'best_practice', 0.88, 'veteran', 'system'),
('VET_SEO: Le page experience trifecta: Core Web Vitals parfaits + 0 intrusive interstitials + mobile-first design = avantage ranking confirme.', 'Page experience trifecta: CWV + 0 interstitials + mobile-first = ranking', 'seo', 'best_practice', 0.88, 'veteran', 'system'),
('VET_SEO: Le internal linking strategy: les pages les plus importantes (pricing, features, signup) doivent avoir le plus de liens internes pointant vers elles.', 'Internal linking: pages importantes (pricing, features, signup) = plus de liens internes', 'seo', 'best_practice', 0.85, 'veteran', 'system'),
('VET_SEO: Le search intent evolution: verifier tous les 3 mois si l intent d un mot-cle a change (de informational a transactional par exemple).', 'Intent evolution: verifier tous 3 mois si intent mot-cle a change', 'seo', 'best_practice', 0.82, 'veteran', 'system'),
('VET_ADS: Le creative brief template: probleme cible → emotion a declencher → message cle → format → CTA → audience → reference visuelle. Avant CHAQUE creative.', 'Creative brief: probleme → emotion → message → format → CTA → audience → ref visuelle', 'ads', 'best_practice', 0.85, 'veteran', 'system'),
('VET_ADS: Le bid strategy evolution: commencer en CPA cible → une fois 50+ conversions, passer en ROAS cible → une fois stable, tester le broad.', 'Bid strategy: CPA cible → 50+ conv → ROAS cible → stable → broad', 'ads', 'best_practice', 0.85, 'veteran', 'system'),
('VET_ADS: Le creative refresh cadence: UGC tous les 7-10j, creatives pro tous les 14-21j, concepts tous les 30j. Pipeline continu obligatoire.', 'Creative refresh: UGC 7-10j, pro 14-21j, concepts 30j. Pipeline continu', 'ads', 'best_practice', 0.85, 'veteran', 'system'),
('VET_ADS: Le audience architecture 5 tiers: cold broad, cold lookalike 1%, warm engaged 30j, hot visitors 7j, super hot cart/pricing 3j.', 'Audience 5 tiers: cold broad, LAL 1%, warm 30j, hot 7j, super hot 3j', 'ads', 'best_practice', 0.88, 'veteran', 'system'),
('VET_ADS: Le Meta Advantage+ shopping campaigns (ASC) surperforment les campagnes manuelles dans 70% des cas en 2026. Tester.', 'Meta ASC surperforment manuelles 70% cas 2026. Tester', 'ads', 'insight', 0.82, 'veteran', 'system'),
('VET_CEO: Le 1-3-1 decision framework: 1 probleme identifie, 3 options possibles, 1 recommandation. Presente au decision maker pour validation rapide.', 'Decision 1-3-1: 1 probleme, 3 options, 1 recommandation = validation rapide', 'ceo', 'best_practice', 0.88, 'veteran', 'system'),
('VET_CEO: Le flywheel thinking: chaque action doit alimenter le systeme. Un client satisfait genere un temoignage, qui genere un lead, qui genere un client.', 'Flywheel: chaque action alimente le systeme. Client → temoignage → lead → client', 'ceo', 'insight', 0.88, 'veteran', 'system'),
('VET_CEO: Le constraint theory: identifier LE goulot d etranglement du business (acquisition? activation? retention? monetization?) et concentrer 80% des efforts dessus.', 'Constraint theory: trouver LE goulot et 80% efforts dessus', 'ceo', 'best_practice', 0.88, 'veteran', 'system'),
('VET_CEO: Le agent coordination protocol: chaque agent envoie ses top 3 insights quotidiens au CEO qui les redistribue aux agents concernes.', 'Agent coordination: 3 insights/jour/agent → CEO redistribue', 'ceo', 'best_practice', 0.90, 'veteran', 'system'),
('VET_CEO: Le weekly growth meeting agenda: 1) metriques vs objectifs, 2) top experiment results, 3) blockers, 4) decisions a prendre, 5) priorities semaine. 30 min max.', 'Weekly growth: metriques + experiments + blockers + decisions + priorities. 30 min', 'ceo', 'best_practice', 0.85, 'veteran', 'system'),
('VET_RETENTION: Le value realization tracking: mesurer si le client obtient la valeur promise. Si non apres 30j, intervention immediate.', 'Value realization: client obtient valeur promise? Non apres 30j = intervention', 'retention', 'best_practice', 0.88, 'veteran', 'system'),
('VET_RETENTION: Le expansion timing science: le meilleur moment pour proposer un upgrade est quand le client vient d obtenir un resultat (pic de satisfaction).', 'Expansion timing: proposer upgrade au pic de satisfaction (apres resultat)', 'retention', 'best_practice', 0.88, 'veteran', 'system'),
('VET_RETENTION: Le churn interview protocol: 5 questions: pourquoi partez-vous? qu aurait-on pu faire mieux? quel outil utilisez-vous maintenant? recommanderiez-vous? qu est-ce qui vous ferait revenir?', 'Churn interview 5 questions: pourquoi + mieux + outil + recommander + revenir', 'retention', 'best_practice', 0.85, 'veteran', 'system'),
('VET_RETENTION: Le customer segmentation by health: green (sain, expand), yellow (attention, nurture), red (risque, save), black (perdu, winback).', 'Segmentation health: green expand, yellow nurture, red save, black winback', 'retention', 'best_practice', 0.85, 'veteran', 'system'),
('VET_ONBOARDING: Le friction elimination: chaque clic, chaque champ, chaque decision entre signup et aha moment doit etre justifie. Si pas essentiel, supprimer.', 'Friction elimination: chaque clic justifie signup→aha. Non essentiel = supprimer', 'onboarding', 'best_practice', 0.90, 'veteran', 'system'),
('VET_ONBOARDING: Le template-first onboarding: proposer des templates pre-configures par secteur = aha moment en 30 secondes au lieu de 5 minutes.', 'Templates par secteur = aha en 30s au lieu de 5 min', 'onboarding', 'best_practice', 0.88, 'veteran', 'system'),
('VET_DM: Le authority-first DM strategy: publier 10+ posts de valeur AVANT de DM quelqu un. Il vous connait deja = taux de reponse 4x.', 'Authority DM: 10+ posts valeur avant DM = 4x reponse', 'dm_instagram', 'best_practice', 0.85, 'veteran', 'system'),
('VET_DM: Le conversation depth scoring: surface chat=1pt, question posee=3pts, besoin revele=5pts, budget mentionne=10pts, RDV fixe=20pts.', 'DM depth scoring: chat 1, question 3, besoin 5, budget 10, RDV 20', 'dm_instagram', 'best_practice', 0.82, 'veteran', 'system'),
('VET_WHATSAPP: Le broadcast segmentation elite: listes par temperature (cold/warm/hot) × type (prospect/client/VIP) × interet (produit A/B/C).', 'WhatsApp broadcast: temperature × type × interet = precision', 'whatsapp', 'best_practice', 0.85, 'veteran', 'system'),
('VET_WHATSAPP: Le after-sales WhatsApp flow: J+1 merci + tips → J+3 satisfaction check → J+7 demande avis → J+14 cross-sell → J+30 referral.', 'After-sales WhatsApp: J1 merci → J3 check → J7 avis → J14 cross-sell → J30 referral', 'whatsapp', 'best_practice', 0.82, 'veteran', 'system'),
('VET_CHATBOT: Le intent-based routing: salutation → accueil, prix → page pricing, support → FAQ ou humain, achat → checkout, plainte → humain immediat.', 'Chatbot routing: salut→accueil, prix→pricing, support→FAQ, achat→checkout, plainte→humain', 'chatbot', 'best_practice', 0.85, 'veteran', 'system'),
('VET_CHATBOT: Le conversation analytics: tracker les top 10 intents, le taux de resolution, le CSAT post-chat, le drop-off point, l escalation rate.', 'Chatbot analytics: top intents + resolution + CSAT + drop-off + escalation', 'chatbot', 'best_practice', 0.85, 'veteran', 'system'),
('VET_GMAPS: Le review response template system: 5 templates positifs (varier!) + 3 templates negatifs (empathie + solution + invitation). Repondre < 24h.', 'GMaps review templates: 5 positifs + 3 negatifs varies. Repondre < 24h', 'gmaps', 'best_practice', 0.85, 'veteran', 'system'),
('VET_GMAPS: Le local pack ranking factors: 1) proximite, 2) pertinence (categories+description), 3) importance (avis+citations+backlinks). Optimiser les 3.', 'Local pack: proximite + pertinence + importance. Optimiser les 3', 'gmaps', 'best_practice', 0.88, 'veteran', 'system'),
('VET_TIKTOK: Le content formula TikTok: hook 0-1s (texte+mouvement) → probleme 1-3s → solution 3-8s → proof 8-12s → CTA 12-15s. Max 15-30s.', 'TikTok formula: hook 0-1s → probleme 1-3s → solution 3-8s → proof → CTA. 15-30s', 'tiktok_comments', 'best_practice', 0.85, 'veteran', 'system'),
('VET_TIKTOK: Le comment strategy: commenter sur les videos virales de sa niche avec des commentaires de valeur. 1 commentaire viral = 1000+ followers.', 'TikTok comments virales niche = 1000+ followers/commentaire', 'tiktok_comments', 'insight', 0.80, 'veteran', 'system'),
('VET_COMPTABLE: Le financial dashboard startup: MRR + ARR + churn % + LTV + CAC + LTV/CAC + burn rate + runway + gross margin + NRR. Les 10 essentiels.', 'Dashboard financier: MRR+ARR+churn+LTV+CAC+ratio+burn+runway+margin+NRR', 'comptable', 'best_practice', 0.88, 'veteran', 'system'),
('VET_COMPTABLE: Le expense categorization SaaS: COGS (serveurs, API) + R&D (dev, product) + S&M (marketing, sales) + G&A (admin, legal). Tracker par categorie.', 'Expenses SaaS: COGS + R&D + S&M + G&A. Tracker par categorie', 'comptable', 'best_practice', 0.85, 'veteran', 'system'),
('VET_RH: Le performance calibration: comparer les notes de performance entre managers pour s assurer de la coherence. Eviter l inflation des notes.', 'Performance calibration: comparer entre managers. Eviter inflation notes', 'rh', 'best_practice', 0.80, 'veteran', 'system'),
('VET_RH: Le stay interview (pourquoi restez-vous? qu est-ce qui pourrait vous faire partir?) est plus utile que l exit interview. Prevenir > guerir.', 'Stay interview: pourquoi restez? quoi ferait partir? Prevenir > guerir', 'rh', 'best_practice', 0.82, 'veteran', 'system'),
('VET_MARKETING: Le brand consistency audit: verifier tous les 3 mois que le logo, les couleurs, le ton, les messages sont identiques sur TOUS les canaux.', 'Brand audit trimestriel: logo+couleurs+ton+messages identiques partout', 'marketing', 'best_practice', 0.82, 'veteran', 'system'),
('VET_MARKETING: Le competitor monitoring system: alertes Google + suivi changelogs + reviews tracking + social mentions + job postings. Surveillance 360°.', 'Competitor monitoring: alertes + changelogs + reviews + social + jobs = 360°', 'marketing', 'best_practice', 0.82, 'veteran', 'system'),
('VET_CROSS: Le data sync protocol: CRM + email tool + analytics + social + support = 1 source de verite. Les donnees silotees tuent les decisions.', 'Data sync: CRM+email+analytics+social+support = 1 source verite. Silos tuent', NULL, 'best_practice', 0.85, 'veteran', 'system'),
('VET_CROSS: Le campaign orchestration: 1 campagne = 1 message coherent sur TOUS les canaux en meme temps. Email + social + ads + DM + WhatsApp synchronises.', 'Campaign orchestration: 1 message coherent tous canaux synchronises', NULL, 'best_practice', 0.85, 'veteran', 'system'),
('VET_CROSS: Le customer 360 view: chaque agent doit avoir acces au profil complet du client (achats, interactions, tickets, score) pour personnaliser.', 'Customer 360: chaque agent accede profil complet pour personnaliser', NULL, 'best_practice', 0.88, 'veteran', 'system'),
('VET_CROSS: Le real-time signal propagation: quand un prospect ouvre un email, l agent DM est notifie pour engager. Quand il visite le pricing, le commercial est alerte.', 'Signal propagation: email ouvert → DM engage. Pricing visite → commercial alerte', NULL, 'best_practice', 0.88, 'veteran', 'system')
